import React, { useState, useEffect, useMemo, useCallback } from "react";
import {
  Gauge, Factory, ShoppingCart, CalendarDays, Settings,
  Plus, Trash2, Snowflake, TrendingUp, TrendingDown, AlertTriangle,
  CheckCircle2, Loader2, ChevronLeft, ChevronRight, Fuel, Clock
} from "lucide-react";
import {
  ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid
} from "recharts";
import { storage } from "./lib/storage.js";

// ---------- helpers ----------
const todayStr = () => new Date().toISOString().slice(0, 10);
const nowTime = () => {
  const d = new Date();
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
};
const uid = () => Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
const LOGO_DATA_URI = "data:image/png;base64,";
const fmt = (n) => Math.round(n || 0).toLocaleString("fr-FR");
const fmtDateLabel = (iso) => {
  const [y, m, d] = iso.split("-");
  return `${d}/${m}`;
};
const dowShort = (iso) => {
  const days = ["Dim", "Lun", "Mar", "Mer", "Jeu", "Ven", "Sam"];
  return days[new Date(iso + "T00:00:00").getDay()];
};

const DEFAULT_CONFIG = {
  stockInitial: 0,
  chargesFixesMois: 417500,
  joursOuvres: 26,
  capaciteCongel: 36,
  prixDetail: 2000,
  prixGros: 1500,
  commission: 150,
  litresPar7h: 20,
  prixGasoil: 1350,
};

// ---------- storage layer ----------
async function loadAll() {
  const out = { config: DEFAULT_CONFIG, production: [], ventes: [], groupe: [] };
  try {
    const c = await storage.get("adglace_config");
    if (c && c.value) out.config = { ...DEFAULT_CONFIG, ...JSON.parse(c.value) };
  } catch (e) { /* not set yet */ }
  try {
    const p = await storage.get("adglace_production");
    if (p && p.value) out.production = JSON.parse(p.value);
  } catch (e) { /* not set yet */ }
  try {
    const v = await storage.get("adglace_ventes");
    if (v && v.value) out.ventes = JSON.parse(v.value);
  } catch (e) { /* not set yet */ }
  try {
    const g = await storage.get("adglace_groupe");
    if (g && g.value) out.groupe = JSON.parse(g.value);
  } catch (e) { /* not set yet */ }
  return out;
}
async function saveConfig(config) {
  await storage.set("adglace_config", JSON.stringify(config));
}
async function saveProduction(list) {
  await storage.set("adglace_production", JSON.stringify(list));
}
async function saveVentes(list) {
  await storage.set("adglace_ventes", JSON.stringify(list));
}
async function saveGroupe(list) {
  await storage.set("adglace_groupe", JSON.stringify(list));
}

// ---------- small UI atoms ----------
const IceCard = ({ children, className = "" }) => (
  <div className={`bg-white/80 backdrop-blur rounded-2xl border border-sky-100 shadow-sm ${className}`}>
    {children}
  </div>
);

const KpiCard = ({ label, value, unit, tone = "sky", icon: Icon }) => {
  const tones = {
    sky: "text-sky-700 bg-sky-50",
    green: "text-emerald-700 bg-emerald-50",
    amber: "text-amber-700 bg-amber-50",
    navy: "text-[#0B2545] bg-slate-50",
  };
  return (
    <IceCard className="p-4 flex flex-col gap-1">
      <div className="flex items-center justify-between">
        <span className="text-[11px] font-medium uppercase tracking-wide text-slate-500">{label}</span>
        {Icon && <span className={`p-1.5 rounded-lg ${tones[tone]}`}><Icon size={14} /></span>}
      </div>
      <div className="font-mono text-2xl font-bold text-[#0B2545] tabular-nums">
        {value}<span className="text-sm font-medium text-slate-400 ml-1">{unit}</span>
      </div>
    </IceCard>
  );
};

// signature element: frost gauge showing freezer stock level vs capacity
const StockGauge = ({ stock, capacity }) => {
  const pct = capacity > 0 ? Math.min(stock / capacity, 1.15) : 0;
  const overCapacity = stock > capacity;
  const r = 54;
  const circ = 2 * Math.PI * r;
  const dash = Math.min(pct, 1) * circ;
  const color = overCapacity ? "#DC6B2F" : pct > 0.8 ? "#E8A33D" : "#2E6DA4";

  return (
    <IceCard className="p-5 relative overflow-hidden">
      <div className="absolute -right-8 -top-8 w-32 h-32 rounded-full bg-sky-100/60 blur-xl" />
      <div className="relative flex items-center gap-5">
        <svg width="132" height="132" viewBox="0 0 132 132" className="shrink-0 -rotate-90">
          <circle cx="66" cy="66" r={r} fill="none" stroke="#E6F1FA" strokeWidth="12" />
          <circle
            cx="66" cy="66" r={r} fill="none" stroke={color} strokeWidth="12"
            strokeDasharray={`${dash} ${circ}`} strokeLinecap="round"
            style={{ transition: "stroke-dasharray 0.6s ease, stroke 0.4s ease" }}
          />
          <text x="66" y="66" textAnchor="middle" transform="rotate(90 66 66)"
                className="font-mono" fontSize="26" fontWeight="700" fill="#0B2545">
            {stock}
          </text>
          <text x="66" y="86" textAnchor="middle" transform="rotate(90 66 66)"
                fontSize="11" fill="#64748B">/ {capacity} blocs</text>
        </svg>
        <div className="flex-1">
          <div className="flex items-center gap-1.5 text-[#0B2545] font-semibold text-sm mb-1">
            <Snowflake size={15} className="text-sky-500" /> Congélateur
          </div>
          {overCapacity ? (
            <div className="flex items-start gap-1.5 text-orange-700 text-xs bg-orange-50 rounded-lg px-2.5 py-2">
              <AlertTriangle size={14} className="shrink-0 mt-0.5" />
              <span>Dépasse la capacité de stockage — écouler en priorité vers la livraison.</span>
            </div>
          ) : pct > 0.8 ? (
            <div className="flex items-start gap-1.5 text-amber-700 text-xs bg-amber-50 rounded-lg px-2.5 py-2">
              <AlertTriangle size={14} className="shrink-0 mt-0.5" />
              <span>Proche de la capacité maximale.</span>
            </div>
          ) : (
            <div className="flex items-start gap-1.5 text-emerald-700 text-xs bg-emerald-50 rounded-lg px-2.5 py-2">
              <CheckCircle2 size={14} className="shrink-0 mt-0.5" />
              <span>Stock sous contrôle.</span>
            </div>
          )}
        </div>
      </div>
    </IceCard>
  );
};

// ---------- Main App ----------
export default function App() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [tab, setTab] = useState("dashboard");
  const [config, setConfig] = useState(DEFAULT_CONFIG);
  const [production, setProduction] = useState([]);
  const [ventes, setVentes] = useState([]);
  const [groupe, setGroupe] = useState([]);
  const [historyDate, setHistoryDate] = useState(todayStr());
  const [error, setError] = useState("");

  useEffect(() => {
    (async () => {
      try {
        const data = await loadAll();
        setConfig(data.config);
        setProduction(data.production);
        setVentes(data.ventes);
        setGroupe(data.groupe);
      } catch (e) {
        setError("Impossible de charger les données. Réessaie dans un instant.");
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  const persist = useCallback(async (nextProduction, nextVentes, nextConfig, nextGroupe) => {
    setSaving(true);
    try {
      if (nextProduction) await saveProduction(nextProduction);
      if (nextVentes) await saveVentes(nextVentes);
      if (nextConfig) await saveConfig(nextConfig);
      if (nextGroupe) await saveGroupe(nextGroupe);
    } catch (e) {
      setError("Échec de l'enregistrement — vérifie ta connexion et réessaie.");
    } finally {
      setSaving(false);
    }
  }, []);

  const addProduction = async (entry) => {
    const next = [...production, { id: uid(), ...entry }];
    setProduction(next);
    await persist(next, null, null, null);
  };
  const deleteProduction = async (id) => {
    const next = production.filter((p) => p.id !== id);
    setProduction(next);
    await persist(next, null, null, null);
  };
  const addVente = async (entry) => {
    const prix = entry.type === "Détail" ? config.prixDetail : config.prixGros;
    const montant = entry.quantite * prix;
    const commission = entry.quantite * config.commission;
    const next = [...ventes, { id: uid(), ...entry, prix, montant, commission }];
    setVentes(next);
    await persist(null, next, null, null);
  };
  const deleteVente = async (id) => {
    const next = ventes.filter((v) => v.id !== id);
    setVentes(next);
    await persist(null, next, null, null);
  };
  const updateConfig = async (patch) => {
    const next = { ...config, ...patch };
    setConfig(next);
    await persist(null, null, next, null);
  };

  const addGroupe = async (entry) => {
    const next = [...groupe, { id: uid(), ...entry }];
    setGroupe(next);
    await persist(null, null, null, next);
  };
  const deleteGroupe = async (id) => {
    const next = groupe.filter((g) => g.id !== id);
    setGroupe(next);
    await persist(null, null, null, next);
  };

  const totalProduced = useMemo(() => production.reduce((s, p) => s + Number(p.blocs || 0), 0), [production]);
  const totalSold = useMemo(() => ventes.reduce((s, v) => s + Number(v.quantite || 0), 0), [ventes]);
  const currentStock = config.stockInitial + totalProduced - totalSold;

  const dayData = (dateStr) => {
    const prod = production.filter((p) => p.date === dateStr);
    const sales = ventes.filter((v) => v.date === dateStr);
    const gpe = groupe.filter((g) => g.date === dateStr);
    const blocsProduits = prod.reduce((s, p) => s + Number(p.blocs || 0), 0);
    const blocsVendus = sales.reduce((s, v) => s + Number(v.quantite || 0), 0);
    const caDetail = sales.filter((v) => v.type === "Détail").reduce((s, v) => s + v.montant, 0);
    const caGros = sales.filter((v) => v.type === "Gros").reduce((s, v) => s + v.montant, 0);
    const caTotal = caDetail + caGros;
    const commission = sales.reduce((s, v) => s + v.commission, 0);
    const chargesJour = config.joursOuvres > 0 ? config.chargesFixesMois / config.joursOuvres : 0;
    const heuresGroupe = gpe.reduce((s, g) => s + Number(g.duree || 0), 0);
    const coutGroupe = gpe.reduce((s, g) => s + Number(g.cout || 0), 0);
    const recetteNette = caTotal - commission - chargesJour - coutGroupe;
    return { prod, sales, gpe, blocsProduits, blocsVendus, caDetail, caGros, caTotal, commission, chargesJour, heuresGroupe, coutGroupe, recetteNette };
  };

  const today = todayStr();
  const todayData = dayData(today);

  const last7 = useMemo(() => {
    const arr = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const iso = d.toISOString().slice(0, 10);
      const dd = dayData(iso);
      arr.push({ date: iso, label: dowShort(iso), CA: dd.caTotal });
    }
    return arr;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [production, ventes, groupe, config]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#EAF4FC]">
        <div className="flex flex-col items-center gap-3 text-[#0B2545]">
          <Loader2 className="animate-spin" size={28} />
          <span className="text-sm font-medium">Chargement d'AD GLACE…</span>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#EAF4FC] flex flex-col font-sans" style={{ maxWidth: 480, margin: "0 auto" }}>
      {/* Header */}
      <header className="bg-[#0B2545] text-white px-5 pt-6 pb-4 rounded-b-3xl shadow-lg relative overflow-hidden">
        <div className="absolute -right-10 -top-10 w-40 h-40 rounded-full bg-sky-500/10" />
        <div className="absolute right-8 top-6 w-16 h-16 rounded-full bg-sky-400/10" />
        <div className="relative flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            <img src={LOGO_DATA_URI} alt="AD GLACE" className="h-11 w-11 object-contain drop-shadow-md shrink-0" />
            <div>
              <h1 className="font-bold text-lg tracking-tight leading-none">AD GLACE</h1>
              <p className="text-sky-200 text-xs mt-1">PK10, Route de Damara — suivi opérationnel</p>
            </div>
          </div>
          <div className="text-right">
            {saving ? (
              <span className="text-[11px] text-sky-300 flex items-center gap-1"><Loader2 size={11} className="animate-spin" /> sync…</span>
            ) : (
              <span className="text-[11px] text-sky-300/80">à jour</span>
            )}
          </div>
        </div>
      </header>

      {error && (
        <div className="mx-4 mt-3 bg-red-50 text-red-700 text-xs rounded-xl px-3 py-2 flex items-center gap-2">
          <AlertTriangle size={14} /> {error}
        </div>
      )}

      {/* Content */}
      <main className="flex-1 px-4 pt-4 pb-24 overflow-y-auto">
        {tab === "dashboard" && (
          <div className="flex flex-col gap-3">
            <StockGauge stock={currentStock} capacity={config.capaciteCongel} />

            <div className="grid grid-cols-2 gap-3">
              <KpiCard label="Produit aujourd'hui" value={fmt(todayData.blocsProduits)} unit="blocs" icon={Factory} tone="sky" />
              <KpiCard label="Vendu aujourd'hui" value={fmt(todayData.blocsVendus)} unit="blocs" icon={ShoppingCart} tone="sky" />
              <KpiCard label="CA du jour" value={fmt(todayData.caTotal)} unit="FCFA" icon={TrendingUp} tone="green" />
              <KpiCard
                label="Recette nette"
                value={fmt(todayData.recetteNette)}
                unit="FCFA"
                icon={todayData.recetteNette >= 0 ? TrendingUp : TrendingDown}
                tone={todayData.recetteNette >= 0 ? "green" : "amber"}
              />
            </div>

            <IceCard className="p-4">
              <div className="text-sm font-semibold text-[#0B2545] mb-2">Chiffre d'affaires — 7 derniers jours</div>
              <div style={{ width: "100%", height: 160 }}>
                <ResponsiveContainer>
                  <BarChart data={last7} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#E6F1FA" vertical={false} />
                    <XAxis dataKey="label" tick={{ fontSize: 11, fill: "#64748B" }} axisLine={false} tickLine={false} />
                    <YAxis tick={{ fontSize: 10, fill: "#94A3B8" }} axisLine={false} tickLine={false} width={40} />
                    <Tooltip
                      formatter={(v) => [`${fmt(v)} FCFA`, "CA"]}
                      labelFormatter={(l, p) => (p && p[0] ? fmtDateLabel(p[0].payload.date) : l)}
                      contentStyle={{ borderRadius: 12, border: "1px solid #E6F1FA", fontSize: 12 }}
                    />
                    <Bar dataKey="CA" fill="#2E6DA4" radius={[6, 6, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </IceCard>

            <IceCard className="p-4">
              <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-1.5 text-sm font-semibold text-[#0B2545]">
                  <Fuel size={15} className="text-amber-600" /> Groupe électrogène — aujourd'hui
                </div>
              </div>
              {todayData.heuresGroupe > 0 ? (
                <div className="flex justify-between text-sm font-mono text-[#0B2545]">
                  <span>{todayData.heuresGroupe.toFixed(1)} h de marche</span>
                  <span>{fmt(todayData.coutGroupe)} FCFA</span>
                </div>
              ) : (
                <p className="text-xs text-slate-400">Pas d'utilisation enregistrée aujourd'hui.</p>
              )}
            </IceCard>

            <IceCard className="p-4">
              <div className="text-sm font-semibold text-[#0B2545] mb-2">Répartition des ventes du jour</div>
              <div className="flex items-center gap-4 text-sm">
                <div className="flex-1">
                  <div className="flex justify-between text-slate-500 text-xs mb-1">
                    <span>Détail ({config.prixDetail} FCFA)</span><span className="font-mono">{fmt(todayData.caDetail)}</span>
                  </div>
                  <div className="flex justify-between text-slate-500 text-xs">
                    <span>Gros ({config.prixGros} FCFA)</span><span className="font-mono">{fmt(todayData.caGros)}</span>
                  </div>
                </div>
              </div>
            </IceCard>
          </div>
        )}

        {tab === "production" && (
          <ProductionTab
            entries={production.filter((p) => p.date === today)}
            onAdd={addProduction}
            onDelete={deleteProduction}
          />
        )}

        {tab === "ventes" && (
          <VentesTab
            entries={ventes.filter((v) => v.date === today)}
            config={config}
            onAdd={addVente}
            onDelete={deleteVente}
          />
        )}

        {tab === "groupe" && (
          <GroupeTab
            entries={groupe.filter((g) => g.date === today)}
            config={config}
            onAdd={addGroupe}
            onDelete={deleteGroupe}
          />
        )}

        {tab === "historique" && (
          <HistoriqueTab
            date={historyDate}
            setDate={setHistoryDate}
            data={dayData(historyDate)}
          />
        )}

        {tab === "reglages" && (
          <ReglagesTab config={config} onUpdate={updateConfig} />
        )}
      </main>

      {/* Bottom nav */}
      <nav className="fixed bottom-0 inset-x-0 mx-auto bg-white border-t border-sky-100 flex justify-around py-2 shadow-[0_-2px_10px_rgba(0,0,0,0.04)]" style={{ maxWidth: 480 }}>
        {[
          { id: "dashboard", label: "Bord", icon: Gauge },
          { id: "production", label: "Prod.", icon: Factory },
          { id: "ventes", label: "Ventes", icon: ShoppingCart },
          { id: "groupe", label: "Groupe", icon: Fuel },
          { id: "historique", label: "Histo.", icon: CalendarDays },
          { id: "reglages", label: "Réglages", icon: Settings },
        ].map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            onClick={() => setTab(id)}
            className={`flex flex-col items-center gap-0.5 px-1.5 py-1 rounded-lg transition-colors ${
              tab === id ? "text-[#0B2545]" : "text-slate-400"
            }`}
          >
            <Icon size={19} strokeWidth={tab === id ? 2.4 : 2} />
            <span className="text-[9.5px] font-medium">{label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

// ---------- Production tab ----------
function ProductionTab({ entries, onAdd, onDelete }) {
  const [form, setForm] = useState({ heure: nowTime(), cycle: 1, blocs: 18, technicien: "" });
  const [submitting, setSubmitting] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    if (!form.blocs || Number(form.blocs) <= 0) return;
    setSubmitting(true);
    await onAdd({ date: todayStr(), heure: form.heure, cycle: Number(form.cycle), blocs: Number(form.blocs), technicien: form.technicien || "—" });
    setForm({ ...form, heure: nowTime() });
    setSubmitting(false);
  };

  return (
    <div className="flex flex-col gap-3">
      <IceCard className="p-4">
        <div className="text-sm font-semibold text-[#0B2545] mb-3">Nouveau démoulage</div>
        <form onSubmit={submit} className="grid grid-cols-2 gap-3">
          <div className="col-span-1">
            <label className="text-[11px] text-slate-500">Heure</label>
            <input type="time" value={form.heure} onChange={(e) => setForm({ ...form, heure: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
          </div>
          <div className="col-span-1">
            <label className="text-[11px] text-slate-500">N° cycle du jour</label>
            <select value={form.cycle} onChange={(e) => setForm({ ...form, cycle: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm bg-white">
              {[1, 2, 3, 4].map((n) => <option key={n} value={n}>Cycle {n}</option>)}
            </select>
          </div>
          <div className="col-span-1">
            <label className="text-[11px] text-slate-500">Blocs produits (15 kg)</label>
            <input type="number" min="0" value={form.blocs} onChange={(e) => setForm({ ...form, blocs: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm font-mono" />
          </div>
          <div className="col-span-1">
            <label className="text-[11px] text-slate-500">Technicien</label>
            <input type="text" placeholder="Nom" value={form.technicien} onChange={(e) => setForm({ ...form, technicien: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
          </div>
          <button type="submit" disabled={submitting}
            className="col-span-2 mt-1 bg-[#2E6DA4] text-white rounded-xl py-2.5 font-semibold text-sm flex items-center justify-center gap-1.5 active:scale-[0.98] transition disabled:opacity-60">
            <Plus size={16} /> Enregistrer le cycle
          </button>
        </form>
      </IceCard>

      <div className="text-xs font-medium text-slate-500 px-1">Aujourd'hui ({entries.length} cycle{entries.length > 1 ? "s" : ""})</div>
      <div className="flex flex-col gap-2">
        {entries.length === 0 && (
          <IceCard className="p-4 text-center text-slate-400 text-sm">Aucun cycle enregistré aujourd'hui.</IceCard>
        )}
        {entries.slice().reverse().map((p) => (
          <IceCard key={p.id} className="p-3 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-lg bg-sky-50 flex items-center justify-center text-sky-700 font-mono text-xs font-bold">C{p.cycle}</div>
              <div>
                <div className="text-sm font-semibold text-[#0B2545] font-mono">{p.blocs} blocs</div>
                <div className="text-[11px] text-slate-500">{p.heure} · {p.technicien}</div>
              </div>
            </div>
            <button onClick={() => onDelete(p.id)} className="text-slate-300 hover:text-red-500 p-1.5">
              <Trash2 size={16} />
            </button>
          </IceCard>
        ))}
      </div>
    </div>
  );
}

// ---------- Ventes tab ----------
function VentesTab({ entries, config, onAdd, onDelete }) {
  const [form, setForm] = useState({ heure: nowTime(), client: "", type: "Détail", quantite: 1 });
  const [submitting, setSubmitting] = useState(false);

  const prixUnitaire = form.type === "Détail" ? config.prixDetail : config.prixGros;
  const montant = Number(form.quantite || 0) * prixUnitaire;
  const commission = Number(form.quantite || 0) * config.commission;

  const submit = async (e) => {
    e.preventDefault();
    if (!form.quantite || Number(form.quantite) <= 0) return;
    setSubmitting(true);
    await onAdd({ date: todayStr(), heure: form.heure, client: form.client || "Client", type: form.type, quantite: Number(form.quantite) });
    setForm({ ...form, heure: nowTime(), client: "", quantite: 1 });
    setSubmitting(false);
  };

  return (
    <div className="flex flex-col gap-3">
      <IceCard className="p-4">
        <div className="text-sm font-semibold text-[#0B2545] mb-3">Nouvelle vente</div>
        <form onSubmit={submit} className="flex flex-col gap-3">
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-[11px] text-slate-500">Heure</label>
              <input type="time" value={form.heure} onChange={(e) => setForm({ ...form, heure: e.target.value })}
                className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
            </div>
            <div>
              <label className="text-[11px] text-slate-500">Type de vente</label>
              <select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value })}
                className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm bg-white">
                <option>Détail</option>
                <option>Gros</option>
              </select>
            </div>
          </div>
          <div>
            <label className="text-[11px] text-slate-500">Client</label>
            <input type="text" placeholder="Ex. Bar Le Manguier" value={form.client} onChange={(e) => setForm({ ...form, client: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
          </div>
          <div>
            <label className="text-[11px] text-slate-500">Quantité (blocs)</label>
            <input type="number" min="1" value={form.quantite} onChange={(e) => setForm({ ...form, quantite: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm font-mono" />
          </div>

          <div className="bg-sky-50 rounded-xl px-3 py-2.5 flex justify-between text-sm font-mono text-[#0B2545]">
            <span>{fmt(montant)} FCFA</span>
            <span className="text-slate-500 text-xs self-center">commission {fmt(commission)} FCFA</span>
          </div>

          <button type="submit" disabled={submitting}
            className="bg-[#2E6DA4] text-white rounded-xl py-2.5 font-semibold text-sm flex items-center justify-center gap-1.5 active:scale-[0.98] transition disabled:opacity-60">
            <Plus size={16} /> Enregistrer la vente
          </button>
        </form>
      </IceCard>

      <div className="text-xs font-medium text-slate-500 px-1">Aujourd'hui ({entries.length} vente{entries.length > 1 ? "s" : ""})</div>
      <div className="flex flex-col gap-2">
        {entries.length === 0 && (
          <IceCard className="p-4 text-center text-slate-400 text-sm">Aucune vente enregistrée aujourd'hui.</IceCard>
        )}
        {entries.slice().reverse().map((v) => (
          <IceCard key={v.id} className="p-3 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className={`w-9 h-9 rounded-lg flex items-center justify-center font-mono text-xs font-bold ${v.type === "Gros" ? "bg-indigo-50 text-indigo-700" : "bg-sky-50 text-sky-700"}`}>
                {v.quantite}b
              </div>
              <div>
                <div className="text-sm font-semibold text-[#0B2545]">{v.client}</div>
                <div className="text-[11px] text-slate-500">{v.heure} · {v.type} · <span className="font-mono">{fmt(v.montant)} FCFA</span></div>
              </div>
            </div>
            <button onClick={() => onDelete(v.id)} className="text-slate-300 hover:text-red-500 p-1.5">
              <Trash2 size={16} />
            </button>
          </IceCard>
        ))}
      </div>
    </div>
  );
}

// ---------- Groupe électrogène tab ----------
function GroupeTab({ entries, config, onAdd, onDelete }) {
  const [form, setForm] = useState({ heureDebut: "06:00", heureFin: "12:00", motif: "" });
  const [submitting, setSubmitting] = useState(false);

  const toHours = (hhmm) => {
    const [h, m] = hhmm.split(":").map(Number);
    return h + m / 60;
  };
  const duree = Math.max(0, toHours(form.heureFin) - toHours(form.heureDebut));
  const litres = duree * (config.litresPar7h / 7);
  const cout = litres * config.prixGasoil;

  const submit = async (e) => {
    e.preventDefault();
    if (duree <= 0) return;
    setSubmitting(true);
    await onAdd({
      date: todayStr(),
      heureDebut: form.heureDebut,
      heureFin: form.heureFin,
      duree,
      litres,
      cout,
      motif: form.motif || "—",
    });
    setForm({ ...form, motif: "" });
    setSubmitting(false);
  };

  const totalDuree = entries.reduce((s, g) => s + Number(g.duree || 0), 0);
  const totalCout = entries.reduce((s, g) => s + Number(g.cout || 0), 0);

  return (
    <div className="flex flex-col gap-3">
      <IceCard className="p-4">
        <div className="text-sm font-semibold text-[#0B2545] mb-1 flex items-center gap-1.5">
          <Fuel size={15} className="text-amber-600" /> Nouvelle période de marche
        </div>
        <p className="text-[11px] text-slate-500 mb-3">
          Base : {config.litresPar7h} L / 7h à {fmt(config.prixGasoil)} FCFA/L, soit ≈ {fmt((config.litresPar7h / 7) * config.prixGasoil)} FCFA/heure.
        </p>
        <form onSubmit={submit} className="flex flex-col gap-3">
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-[11px] text-slate-500">Heure de mise en marche</label>
              <input type="time" value={form.heureDebut} onChange={(e) => setForm({ ...form, heureDebut: e.target.value })}
                className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
            </div>
            <div>
              <label className="text-[11px] text-slate-500">Heure d'arrêt</label>
              <input type="time" value={form.heureFin} onChange={(e) => setForm({ ...form, heureFin: e.target.value })}
                className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
            </div>
          </div>
          <div>
            <label className="text-[11px] text-slate-500">Motif (coupure ENERCA, secours solaire...)</label>
            <input type="text" placeholder="Ex. coupure ENERCA imprévue" value={form.motif}
              onChange={(e) => setForm({ ...form, motif: e.target.value })}
              className="w-full mt-1 rounded-lg border border-sky-100 px-2.5 py-2 text-sm" />
          </div>

          <div className="bg-amber-50 rounded-xl px-3 py-2.5 flex items-center justify-between text-sm font-mono text-[#0B2545]">
            <span className="flex items-center gap-1"><Clock size={13} /> {duree.toFixed(1)} h</span>
            <span>{litres.toFixed(1)} L</span>
            <span className="font-semibold">{fmt(cout)} FCFA</span>
          </div>

          <button type="submit" disabled={submitting || duree <= 0}
            className="bg-amber-600 text-white rounded-xl py-2.5 font-semibold text-sm flex items-center justify-center gap-1.5 active:scale-[0.98] transition disabled:opacity-60">
            <Plus size={16} /> Enregistrer cette période
          </button>
        </form>
      </IceCard>

      <div className="grid grid-cols-2 gap-3">
        <KpiCard label="Heures groupe (jour)" value={totalDuree.toFixed(1)} unit="h" icon={Clock} tone="amber" />
        <KpiCard label="Coût gasoil (jour)" value={fmt(totalCout)} unit="FCFA" icon={Fuel} tone="amber" />
      </div>

      <div className="text-xs font-medium text-slate-500 px-1">Aujourd'hui ({entries.length} période{entries.length > 1 ? "s" : ""})</div>
      <div className="flex flex-col gap-2">
        {entries.length === 0 && (
          <IceCard className="p-4 text-center text-slate-400 text-sm">Aucune marche du groupe enregistrée aujourd'hui.</IceCard>
        )}
        {entries.slice().reverse().map((g) => (
          <IceCard key={g.id} className="p-3 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-lg bg-amber-50 flex items-center justify-center text-amber-700">
                <Fuel size={16} />
              </div>
              <div>
                <div className="text-sm font-semibold text-[#0B2545] font-mono">{g.heureDebut} → {g.heureFin}</div>
                <div className="text-[11px] text-slate-500">{g.duree.toFixed(1)} h · {g.litres.toFixed(1)} L · {fmt(g.cout)} FCFA · {g.motif}</div>
              </div>
            </div>
            <button onClick={() => onDelete(g.id)} className="text-slate-300 hover:text-red-500 p-1.5">
              <Trash2 size={16} />
            </button>
          </IceCard>
        ))}
      </div>
    </div>
  );
}

// ---------- Historique tab ----------
function HistoriqueTab({ date, setDate, data }) {
  const shiftDate = (delta) => {
    const d = new Date(date + "T00:00:00");
    d.setDate(d.getDate() + delta);
    setDate(d.toISOString().slice(0, 10));
  };
  return (
    <div className="flex flex-col gap-3">
      <IceCard className="p-3 flex items-center justify-between">
        <button onClick={() => shiftDate(-1)} className="p-2 text-slate-500"><ChevronLeft size={18} /></button>
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)}
          className="text-sm font-semibold text-[#0B2545] text-center border-none bg-transparent" />
        <button onClick={() => shiftDate(1)} className="p-2 text-slate-500"><ChevronRight size={18} /></button>
      </IceCard>

      <div className="grid grid-cols-2 gap-3">
        <KpiCard label="Produit" value={fmt(data.blocsProduits)} unit="blocs" icon={Factory} tone="sky" />
        <KpiCard label="Vendu" value={fmt(data.blocsVendus)} unit="blocs" icon={ShoppingCart} tone="sky" />
        <KpiCard label="CA total" value={fmt(data.caTotal)} unit="FCFA" icon={TrendingUp} tone="green" />
        <KpiCard label="Recette nette" value={fmt(data.recetteNette)} unit="FCFA"
          icon={data.recetteNette >= 0 ? TrendingUp : TrendingDown} tone={data.recetteNette >= 0 ? "green" : "amber"} />
      </div>

      <IceCard className="p-4">
        <div className="text-sm font-semibold text-[#0B2545] mb-2">Détail des charges du jour</div>
        <div className="text-xs text-slate-600 flex flex-col gap-1 font-mono">
          <div className="flex justify-between"><span className="font-sans text-slate-500">CA détail</span><span>{fmt(data.caDetail)} FCFA</span></div>
          <div className="flex justify-between"><span className="font-sans text-slate-500">CA gros</span><span>{fmt(data.caGros)} FCFA</span></div>
          <div className="flex justify-between"><span className="font-sans text-slate-500">− Commission</span><span>{fmt(data.commission)} FCFA</span></div>
          <div className="flex justify-between"><span className="font-sans text-slate-500">− Charges fixes / jour</span><span>{fmt(data.chargesJour)} FCFA</span></div>
          <div className="flex justify-between"><span className="font-sans text-slate-500">− Groupe électrogène ({data.heuresGroupe.toFixed(1)} h)</span><span>{fmt(data.coutGroupe)} FCFA</span></div>
        </div>
      </IceCard>

      <div className="text-xs font-medium text-slate-500 px-1">Cycles de production ({data.prod.length})</div>
      <div className="flex flex-col gap-2">
        {data.prod.length === 0 && <IceCard className="p-3 text-center text-slate-400 text-sm">Aucun cycle ce jour-là.</IceCard>}
        {data.prod.map((p) => (
          <IceCard key={p.id} className="p-3 text-sm flex justify-between">
            <span>Cycle {p.cycle} · {p.heure} · {p.technicien}</span>
            <span className="font-mono font-semibold">{p.blocs} blocs</span>
          </IceCard>
        ))}
      </div>

      <div className="text-xs font-medium text-slate-500 px-1">Ventes ({data.sales.length})</div>
      <div className="flex flex-col gap-2">
        {data.sales.length === 0 && <IceCard className="p-3 text-center text-slate-400 text-sm">Aucune vente ce jour-là.</IceCard>}
        {data.sales.map((v) => (
          <IceCard key={v.id} className="p-3 text-sm flex justify-between">
            <span>{v.client} · {v.type} · {v.heure}</span>
            <span className="font-mono font-semibold">{v.quantite}b · {fmt(v.montant)} FCFA</span>
          </IceCard>
        ))}
      </div>

      <div className="text-xs font-medium text-slate-500 px-1">Groupe électrogène ({data.gpe.length})</div>
      <div className="flex flex-col gap-2">
        {data.gpe.length === 0 && <IceCard className="p-3 text-center text-slate-400 text-sm">Groupe non utilisé ce jour-là.</IceCard>}
        {data.gpe.map((g) => (
          <IceCard key={g.id} className="p-3 text-sm flex justify-between">
            <span>{g.heureDebut} → {g.heureFin} · {g.motif}</span>
            <span className="font-mono font-semibold">{g.duree.toFixed(1)} h · {fmt(g.cout)} FCFA</span>
          </IceCard>
        ))}
      </div>
    </div>
  );
}

// ---------- Réglages tab ----------
function ReglagesTab({ config, onUpdate }) {
  const [local, setLocal] = useState(config);
  const [savedFlash, setSavedFlash] = useState(false);

  const field = (key, label, unit) => (
    <div className="flex items-center justify-between py-2.5 border-b border-sky-50 last:border-0">
      <span className="text-sm text-slate-600">{label}</span>
      <div className="flex items-center gap-1">
        <input
          type="number"
          value={local[key]}
          onChange={(e) => setLocal({ ...local, [key]: Number(e.target.value) })}
          className="w-24 text-right rounded-lg border border-sky-100 px-2 py-1.5 text-sm font-mono"
        />
        <span className="text-[11px] text-slate-400 w-10">{unit}</span>
      </div>
    </div>
  );

  const save = async () => {
    await onUpdate(local);
    setSavedFlash(true);
    setTimeout(() => setSavedFlash(false), 1500);
  };

  return (
    <div className="flex flex-col gap-3">
      <IceCard className="p-4">
        <div className="text-sm font-semibold text-[#0B2545] mb-1">Paramètres du modèle</div>
        <p className="text-[11px] text-slate-500 mb-2">Ces valeurs alimentent tous les calculs automatiques (prix, commission, seuils).</p>
        {field("prixDetail", "Prix détail", "FCFA")}
        {field("prixGros", "Prix gros (≥10 blocs)", "FCFA")}
        {field("commission", "Commission / bloc", "FCFA")}
        {field("chargesFixesMois", "Charges fixes", "FCFA/m")}
        {field("joursOuvres", "Jours ouvrés", "j/mois")}
        {field("capaciteCongel", "Capacité congélateur", "blocs")}
        {field("stockInitial", "Stock initial de départ", "blocs")}
        {field("litresPar7h", "Consommation groupe", "L/7h")}
        {field("prixGasoil", "Prix du gasoil", "FCFA/L")}
        <button onClick={save}
          className="w-full mt-3 bg-[#0B2545] text-white rounded-xl py-2.5 font-semibold text-sm active:scale-[0.98] transition">
          {savedFlash ? "Enregistré ✓" : "Enregistrer les réglages"}
        </button>
      </IceCard>

      <IceCard className="p-4 text-xs text-slate-500 leading-relaxed">
        <b className="text-[#0B2545]">À savoir :</b> les données de production et de ventes sont partagées entre tous les
        appareils qui ouvrent cette application (toi, le technicien, la commerciale) — utile pour un suivi à distance,
        mais garde le lien de l'application privé, comme tu le ferais pour un cahier de comptes.
      </IceCard>
    </div>
  );
}
